def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about an artist (or related entities) into a single,
    fluent English sentence. Handles a variety of predicates and creates complex
    sentences with relative clauses to connect related facts.
    """
    if not triples:
        return ""

    # Identify the main subject (most frequent subject)
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1

    main_subject = max(subject_counts, key=subject_counts.get) if subject_counts else ""

    # Group triples by subject
    subject_triples = {}
    for t in triples:
        if t.subject not in subject_triples:
            subject_triples[t.subject] = []
        subject_triples[t.subject].append(t)

    # Build sentence components
    main_info = []
    location_info = []
    other_info = []

    # Process main subject triples
    for t in subject_triples.get(main_subject, []):
        phrase = build_phrase(t)
        if t.predicate in ["country", "birthPlace", "deathPlace", "origin", "location", "isPartOf"]:
            location_info.append(phrase)
        elif t.predicate in ["capital", "leader", "governingBody"]:
            other_info.append(phrase)
        else:
            main_info.append(phrase)

    # Build the sentence
    parts = []

    # Start with main subject name and primary info
    if main_info:
        parts.append(main_info[0])
        for phrase in main_info[1:]:
            parts.append(f", {phrase}")

    # Add location info with relative clauses
    if location_info:
        loc_text = " ".join(location_info)
        if parts:
            parts.append(f" which is located {loc_text}")
        else:
            parts.append(f"{main_subject} is located {loc_text}")

    # Add other info
    if other_info:
        for phrase in other_info:
            if parts:
                parts.append(f", {phrase}")
            else:
                parts.append(phrase)

    return " ".join(parts) + "." if parts else ""

def build_phrase(triple: Triple) -> str:
    """Build a natural language phrase from a triple."""
    subject, predicate, obj = triple.subject, triple.predicate, triple.object

    # Person-related predicates
    if predicate == "birthDate":
        return f"{subject} was born on {obj}"
    elif predicate == "birthYear":
        return f"{subject} was born in {obj}"
    elif predicate == "deathDate":
        return f"{subject} died on {obj}"
    elif predicate == "deathPlace":
        return f"{subject} died in {obj}"
    elif predicate == "birthPlace":
        return f"{subject} was born in {obj}"
    elif predicate == "origin":
        return f"{subject} originates from {obj}"
    elif predicate == "nationality":
        return f"{subject} is {obj}"
    elif predicate == "occupation":
        return f"{subject} works as a {obj}"
    elif predicate == "genre":
        return f"{subject} performs {obj}"
    elif predicate == "instrument":
        return f"{subject} plays the {obj}"
    elif predicate == "associatedBand/associatedMusicalArtist":
        return f"{subject} is associated with {obj}"
    elif predicate == "recordLabel":
        return f"{subject} is signed to {obj}"
    elif predicate == "activeYearsStartYear":
        return f"{subject} started in {obj}"
    elif predicate == "activeYearsEndYear":
        return f"{subject} ended in {obj}"
    elif predicate == "background":
        return f"a {obj}"
    elif predicate == "alternativeName":
        return f"also known as {obj}"
    elif predicate == "professionalField":
        return f"working in {obj}"
    elif predicate == "training":
        return f"trained at {obj}"

    # Location/Geography predicates
    elif predicate == "country":
        return f"in {obj}"
    elif predicate == "capital":
        return f"whose capital is {obj}"
    elif predicate == "location":
        return f"located in {obj}"
    elif predicate == "isPartOf":
        return f"part of {obj}"
    elif predicate == "leader":
        return f"led by {obj}"
    elif predicate == "governingBody":
        return f"governed by {obj}"

    # Music/Industry predicates
    elif predicate == "parentCompany":
        return f"owned by {obj}"
    elif predicate == "distributingCompany":
        return f"distributed by {obj}"
    elif predicate == "bandMember":
        return f"including {obj}"
    elif predicate == "musicFusionGenre":
        return f"fusing {obj}"
    elif predicate == "musicSubgenre":
        return f"a subgenre of {obj}"
    elif predicate == "stylisticOrigin":
        return f"originating from {obj}"
    elif predicate == "derivative":
        return f"influencing {obj}"

    # Other predicates
    elif predicate == "language":
        return f"with {obj}"
    elif predicate == "officialLanguage":
        return f"with official language {obj}"
    elif predicate == "ethnicGroup":
        return f"with {obj} ethnic group"
    elif predicate == "populationDensity":
        return f"with population density {obj}"
    elif predicate == "meaning":
        return f"meaning {obj}"
    elif predicate == "longName":
        return f"long name {obj}"
    elif predicate == "areaTotal":
        return f"covering {obj}"
    elif predicate == "foundingDate":
        return f"founded in {obj}"
    elif predicate == "elevationAboveTheSeaLevel":
        return f"at {obj} above sea level"
    elif predicate == "postalCode":
        return f"with postal codes {obj}"
    elif predicate == "demonym":
        return f"residents called {obj}"
    elif predicate == "currency":
        return f"using {obj}"
    elif predicate == "anthem":
        return f"anthem {obj}"
    elif predicate == "leaderTitle":
        return f"with leader title {obj}"

    # Default fallback
    return f"{subject} {predicate} {obj}"

